                ". Must start with letter/underscore and contain only letters, digits, or underscores.");
        }

        // Validate and sanitize column type
        String safeColumnType = (columnType == null) ? null : columnType.trim();
        if (safeColumnType == null || safeColumnType.isEmpty()) {
            throw new IllegalArgumentException("Column type cannot be null or empty");
        }
        if (!safeColumnType.matches("^[a-zA-Z0-9(),. ]+$")) {
            throw new IllegalArgumentException("Invalid column type: " + safeColumnType + 
                ". Must contain only letters, digits, parentheses, commas, periods, or spaces.");
        }

        // Construct and execute ALTER TABLE statement
        String sql = "ALTER TABLE products ADD COLUMN " + safeColumnName + " " + safeColumnType;
        try {
            jdbcTemplate.execute(sql);
        } catch (DataAccessException e) {
            throw new RuntimeException("Failed to add column '" + safeColumnName + 
                "' to products table. Type: " + safeColumnType, e);
        }
    }
}
